DROP TABLE IF EXISTS norms;
CREATE TABLE norms (
    
    relation_name TEXT NOT NULL,
    join_var_name TEXT NOT NULL,
    aggregator_name TEXT NOT NULL,
    pred_col_name TEXT,
    pk_relation_name TEXT,
    fk_join_var_name TEXT,
    pk_join_var_name TEXT,
    
    pred_value_id      INTEGER,
    l0 DOUBLE,
    l1 DOUBLE,
    l2 DOUBLE,
    l3 DOUBLE,
    l_inf DOUBLE
);

----------------------------------
-- START: generate all mcvs and histograms
----------------------------------


DROP TABLE IF EXISTS AKA_NAME_NAME_mcv;

-- Create MCV table for AKA_NAME.NAME, with a unique mcv_id
CREATE TABLE AKA_NAME_NAME_mcv AS
WITH base AS (
    SELECT NAME, COUNT(*) AS freq
    FROM AKA_NAME
    WHERE NAME IS NOT NULL
    GROUP BY NAME
    ORDER BY freq DESC
    LIMIT 5000
)
SELECT
    ROW_NUMBER() OVER (ORDER BY freq DESC) AS mcv_id,
    NAME,
    freq
FROM base;

