DROP TABLE IF EXISTS AKA_NAME_PERSON_ID_ID_NAME;

-- Create temp table AKA_NAME_PERSON_ID_ID_NAME (FK->PK join)
CREATE TEMP TABLE AKA_NAME_PERSON_ID_ID_NAME AS
SELECT
    AKA_NAME.ID AS ID, AKA_NAME.PERSON_ID AS PERSON_ID,
    NAME.GENDER AS NAME_GENDER, NAME.NAME AS NAME_NAME, NAME.NAME_PCODE_CF AS NAME_NAME_PCODE_CF
FROM AKA_NAME
JOIN NAME
  ON AKA_NAME.PERSON_ID = NAME.ID
;

DROP TABLE IF EXISTS Degree_AKA_NAME_ID;

-- Create aggregator table Degree_AKA_NAME_ID
CREATE TEMP TABLE Degree_AKA_NAME_ID AS
SELECT
    AKA_NAME.ID AS ID,
    COUNT(*) AS deg
FROM AKA_NAME

WHERE AKA_NAME.ID IS NOT NULL
GROUP BY
    AKA_NAME.ID
HAVING COUNT(*) > 0
ORDER BY deg DESC
;

INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    
    pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'AKA_NAME' AS relation_name,
    'ID' AS join_var_name,
    'NOPRED' AS aggregator_name,
    NULL AS pred_col_name,
    
    1 AS pred_value_id,
  COUNT(*) AS l0,
  SUM(POWER(deg, 1)) AS l1,
  SUM(POWER(deg, 2)) AS l2,
  SUM(POWER(deg, 3)) AS l3,
  MAX(deg) AS l_inf
FROM (
  SELECT * FROM Degree_AKA_NAME_ID
  LIMIT 1
);

