-- Create aggregator table Degree_AKA_NAME_PERSON_ID_ID_NAME_NAME_PCODE_CF_ID for Histogram AKA_NAME_PERSON_ID_ID_NAME.NAME_NAME_PCODE_CF -- FKPK_RANGE
CREATE TEMP TABLE Degree_AKA_NAME_PERSON_ID_ID_NAME_NAME_PCODE_CF_ID AS
SELECT
    AKA_NAME_PERSON_ID_ID_NAME.NAME_NAME_PCODE_CF AS NAME_PCODE_CF,
    AKA_NAME_PERSON_ID_ID_NAME.ID AS ID,
    COUNT(*) AS deg
FROM AKA_NAME_PERSON_ID_ID_NAME

WHERE AKA_NAME_PERSON_ID_ID_NAME.ID IS NOT NULL
GROUP BY
    AKA_NAME_PERSON_ID_ID_NAME.NAME_NAME_PCODE_CF, AKA_NAME_PERSON_ID_ID_NAME.ID
;

INSERT INTO norms(

    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
pred_value_id,
l0, l1, l2, l3, l_inf
)
SELECT
    
    'AKA_NAME' AS relation_name,
    'ID' AS join_var_name,
    'RANGE' AS aggregator_name,
    'NAME_PCODE_CF' AS pred_col_name,
    'PERSON_ID' AS fk_join_var_name,
    'NAME' AS pk_relation_name,
    'ID' AS pk_join_var_name,
    
    bucket_id     AS pred_value,
    COUNT(*) AS l0,
    SUM(POWER(deg, 1)) AS l1,
    SUM(POWER(deg, 2)) AS l2,
    SUM(POWER(deg, 3)) AS l3,
    MAX(deg) AS l_inf
FROM 
(
  SELECT
        ID, bucket_id, SUM(deg) as deg
        FROM Degree_AKA_NAME_PERSON_ID_ID_NAME_NAME_PCODE_CF_ID d
        JOIN NAME_NAME_PCODE_CF_histogram h
        ON (h.lower_bound IS NULL OR d.NAME_PCODE_CF >= h.lower_bound)
        AND (h.upper_bound IS NULL OR d.NAME_PCODE_CF <= h.upper_bound)
    WHERE ID IS NOT NULL AND bucket_id IS NOT NULL
    GROUP BY ID, bucket_id
)
GROUP BY bucket_id
ORDER BY bucket_id
;

DROP TABLE IF EXISTS Degree_AKA_NAME_PERSON_ID;

-- Create aggregator table Degree_AKA_NAME_PERSON_ID
CREATE TEMP TABLE Degree_AKA_NAME_PERSON_ID AS
SELECT
    AKA_NAME.PERSON_ID AS PERSON_ID,
    COUNT(*) AS deg
FROM AKA_NAME

WHERE AKA_NAME.PERSON_ID IS NOT NULL
GROUP BY
    AKA_NAME.PERSON_ID
HAVING COUNT(*) > 0
ORDER BY deg DESC
;

