DROP TABLE IF EXISTS AKA_TITLE_MOVIE_ID_ID_TITLE;

-- Create temp table AKA_TITLE_MOVIE_ID_ID_TITLE (FK->PK join)
CREATE TEMP TABLE AKA_TITLE_MOVIE_ID_ID_TITLE AS
SELECT
    AKA_TITLE.ID AS ID, AKA_TITLE.MOVIE_ID AS MOVIE_ID, AKA_TITLE.KIND_ID AS KIND_ID,
    TITLE.TITLE AS TITLE_TITLE, TITLE.PRODUCTION_YEAR AS TITLE_PRODUCTION_YEAR, TITLE.EPISODE_NR AS TITLE_EPISODE_NR
FROM AKA_TITLE
JOIN TITLE
  ON AKA_TITLE.MOVIE_ID = TITLE.ID
;

DROP TABLE IF EXISTS Degree_AKA_TITLE_ID;

-- Create aggregator table Degree_AKA_TITLE_ID
CREATE TEMP TABLE Degree_AKA_TITLE_ID AS
SELECT
    AKA_TITLE.ID AS ID,
    COUNT(*) AS deg
FROM AKA_TITLE

WHERE AKA_TITLE.ID IS NOT NULL
GROUP BY
    AKA_TITLE.ID
HAVING COUNT(*) > 0
ORDER BY deg DESC
;

