        ON (h.lower_bound IS NULL OR d.NAME_PCODE_CF >= h.lower_bound)
        AND (h.upper_bound IS NULL OR d.NAME_PCODE_CF <= h.upper_bound)
    WHERE PERSON_ID IS NOT NULL AND bucket_id IS NOT NULL
    GROUP BY PERSON_ID, bucket_id
)
GROUP BY bucket_id
ORDER BY bucket_id
;

DROP TABLE IF EXISTS Degree_CAST_INFO_PERSON_ROLE_ID_ID_CHAR_NAME_NAME_PERSON_ID;

-- Create aggregator table Degree_CAST_INFO_PERSON_ROLE_ID_ID_CHAR_NAME_NAME_PERSON_ID for MCV CAST_INFO_PERSON_ROLE_ID_ID_CHAR_NAME.CHAR_NAME_NAME -- FKPK_MCV
CREATE TEMP TABLE Degree_CAST_INFO_PERSON_ROLE_ID_ID_CHAR_NAME_NAME_PERSON_ID AS
SELECT
    mcvt.mcv_id AS mcv_id,
    CAST_INFO_PERSON_ROLE_ID_ID_CHAR_NAME.PERSON_ID AS PERSON_ID,
    COUNT(*) AS deg
FROM CAST_INFO_PERSON_ROLE_ID_ID_CHAR_NAME
JOIN CHAR_NAME_NAME_mcv mcvt ON CAST_INFO_PERSON_ROLE_ID_ID_CHAR_NAME.CHAR_NAME_NAME = mcvt.NAME
WHERE CAST_INFO_PERSON_ROLE_ID_ID_CHAR_NAME.PERSON_ID IS NOT NULL
GROUP BY
    mcvt.mcv_id, CAST_INFO_PERSON_ROLE_ID_ID_CHAR_NAME.PERSON_ID
;

INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'CAST_INFO' AS relation_name,
    'PERSON_ID' AS join_var_name,
    'MCV' AS aggregator_name,
    'NAME' AS pred_col_name,
    'PERSON_ROLE_ID' AS fk_join_var_name,
    'CHAR_NAME' AS pk_relation_name,
    'ID' AS pk_join_var_name,
    
    mcv_id AS pred_value,
    COUNT(*) AS l0,
    SUM(POWER(deg, 1)) AS l1,
    SUM(POWER(deg, 2)) AS l2,
    SUM(POWER(deg, 3)) AS l3,
    MAX(deg) AS l_inf
FROM Degree_CAST_INFO_PERSON_ROLE_ID_ID_CHAR_NAME_NAME_PERSON_ID
GROUP BY mcv_id
;

