DROP TABLE IF EXISTS Degree_CAST_INFO_NOTE_PERSON_ROLE_ID;

-- Create aggregator table Degree_CAST_INFO_NOTE_PERSON_ROLE_ID for MCV CAST_INFO.NOTE -- MCV
CREATE TEMP TABLE Degree_CAST_INFO_NOTE_PERSON_ROLE_ID AS
SELECT
    mcvt.mcv_id AS mcv_id,
    CAST_INFO.PERSON_ROLE_ID AS PERSON_ROLE_ID,
    COUNT(*) AS deg
FROM CAST_INFO
JOIN CAST_INFO_NOTE_mcv mcvt ON CAST_INFO.NOTE = mcvt.NOTE
WHERE CAST_INFO.PERSON_ROLE_ID IS NOT NULL
GROUP BY
    mcvt.mcv_id, CAST_INFO.PERSON_ROLE_ID
;

