CREATE TEMP TABLE Degree_COMPANY_NAME_COUNTRY_CODE_ID AS
SELECT
    COMPANY_NAME.COUNTRY_CODE AS COUNTRY_CODE,
    COMPANY_NAME.ID AS ID,
    COUNT(*) AS deg
FROM COMPANY_NAME
LEFT JOIN COMPANY_NAME_COUNTRY_CODE_mcv mcvt ON COMPANY_NAME.COUNTRY_CODE = mcvt.COUNTRY_CODE
WHERE COMPANY_NAME.ID IS NOT NULL AND mcvt.mcv_id IS NULL 
GROUP BY
    COMPANY_NAME.COUNTRY_CODE, COMPANY_NAME.ID
;

-- Insert into norms for Non-MCV COMPANY_NAME COUNTRY_CODE ID NONMCV
-- Among all non-MCV values in Degree_COMPANY_NAME_COUNTRY_CODE_ID, find max of each Lp
WITH perValue AS (
  SELECT
    COUNTRY_CODE,
    COUNT(*) AS l0, SUM(POWER(deg, 1)) AS l1, SUM(POWER(deg, 2)) AS l2, SUM(POWER(deg, 3)) AS l3, MAX(deg) AS l_inf
  FROM Degree_COMPANY_NAME_COUNTRY_CODE_ID
  GROUP BY COUNTRY_CODE
  HAVING COUNTRY_CODE IS NOT NULL
)
INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'COMPANY_NAME' AS relation_name,
    'ID' AS join_var_name,
    'NONMCV' AS aggregator_name,
    'COUNTRY_CODE' AS pred_col_name,
    NULL AS fk_join_var_name,
    NULL AS pk_relation_name,
    NULL AS pk_join_var_name,
    
  NULL              AS pred_value_id,
  MAX(l0) AS l0, MAX(l1) AS l1, MAX(l2) AS l2, MAX(l3) AS l3, MAX(l_inf) AS l_inf
FROM perValue
HAVING COUNT(*) > 0  -- If you need to ensure some rows are returned
;

