    COUNT(*) AS deg
FROM COMPLETE_CAST_MOVIE_ID_ID_TITLE
JOIN TITLE_PRODUCTION_YEAR_mcv mcvt ON COMPLETE_CAST_MOVIE_ID_ID_TITLE.TITLE_PRODUCTION_YEAR = mcvt.PRODUCTION_YEAR
WHERE COMPLETE_CAST_MOVIE_ID_ID_TITLE.MOVIE_ID IS NOT NULL
GROUP BY
