    COMPLETE_CAST_MOVIE_ID_ID_TITLE.TITLE_PRODUCTION_YEAR AS PRODUCTION_YEAR,
    COMPLETE_CAST_MOVIE_ID_ID_TITLE.MOVIE_ID AS MOVIE_ID,
