CREATE TEMP TABLE Degree_COMPLETE_CAST_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_SUBJECT_ID AS
SELECT
    COMPLETE_CAST_MOVIE_ID_ID_TITLE.TITLE_PRODUCTION_YEAR AS PRODUCTION_YEAR,
    COMPLETE_CAST_MOVIE_ID_ID_TITLE.SUBJECT_ID AS SUBJECT_ID,
    COUNT(*) AS deg
FROM COMPLETE_CAST_MOVIE_ID_ID_TITLE
LEFT JOIN TITLE_PRODUCTION_YEAR_mcv mcvt ON COMPLETE_CAST_MOVIE_ID_ID_TITLE.TITLE_PRODUCTION_YEAR = mcvt.PRODUCTION_YEAR
WHERE COMPLETE_CAST_MOVIE_ID_ID_TITLE.SUBJECT_ID IS NOT NULL AND mcvt.mcv_id IS NULL 
GROUP BY
    COMPLETE_CAST_MOVIE_ID_ID_TITLE.TITLE_PRODUCTION_YEAR, COMPLETE_CAST_MOVIE_ID_ID_TITLE.SUBJECT_ID
;

-- Insert into norms for Non-MCV COMPLETE_CAST_MOVIE_ID_ID_TITLE PRODUCTION_YEAR SUBJECT_ID NONMCV
-- Among all non-MCV values in Degree_COMPLETE_CAST_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_SUBJECT_ID, find max of each Lp
WITH perValue AS (
  SELECT
    PRODUCTION_YEAR,
    COUNT(*) AS l0, SUM(POWER(deg, 1)) AS l1, SUM(POWER(deg, 2)) AS l2, SUM(POWER(deg, 3)) AS l3, MAX(deg) AS l_inf
  FROM Degree_COMPLETE_CAST_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_SUBJECT_ID
  GROUP BY PRODUCTION_YEAR
  HAVING PRODUCTION_YEAR IS NOT NULL
)
INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'COMPLETE_CAST' AS relation_name,
    'SUBJECT_ID' AS join_var_name,
    'NONMCV' AS aggregator_name,
    'PRODUCTION_YEAR' AS pred_col_name,
    'MOVIE_ID' AS fk_join_var_name,
    'TITLE' AS pk_relation_name,
    'ID' AS pk_join_var_name,
    
  NULL              AS pred_value_id,
  MAX(l0) AS l0, MAX(l1) AS l1, MAX(l2) AS l2, MAX(l3) AS l3, MAX(l_inf) AS l_inf
FROM perValue
HAVING COUNT(*) > 0  -- If you need to ensure some rows are returned
;

