FROM COMPLETE_CAST_MOVIE_ID_ID_TITLE

WHERE COMPLETE_CAST_MOVIE_ID_ID_TITLE.STATUS_ID IS NOT NULL
GROUP BY
    COMPLETE_CAST_MOVIE_ID_ID_TITLE.TITLE_EPISODE_NR, COMPLETE_CAST_MOVIE_ID_ID_TITLE.STATUS_ID
;

INSERT INTO norms(

    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
pred_value_id,
l0, l1, l2, l3, l_inf
)
SELECT
    
    'COMPLETE_CAST' AS relation_name,
    'STATUS_ID' AS join_var_name,
    'RANGE' AS aggregator_name,
    'EPISODE_NR' AS pred_col_name,
    'MOVIE_ID' AS fk_join_var_name,
    'TITLE' AS pk_relation_name,
    'ID' AS pk_join_var_name,
    
    bucket_id     AS pred_value,
    COUNT(*) AS l0,
    SUM(POWER(deg, 1)) AS l1,
    SUM(POWER(deg, 2)) AS l2,
    SUM(POWER(deg, 3)) AS l3,
    MAX(deg) AS l_inf
FROM 
(
  SELECT
        STATUS_ID, bucket_id, SUM(deg) as deg
        FROM Degree_COMPLETE_CAST_MOVIE_ID_ID_TITLE_EPISODE_NR_STATUS_ID d
        JOIN TITLE_EPISODE_NR_histogram h
        ON (h.lower_bound IS NULL OR d.EPISODE_NR >= h.lower_bound)
        AND (h.upper_bound IS NULL OR d.EPISODE_NR <= h.upper_bound)
    WHERE STATUS_ID IS NOT NULL AND bucket_id IS NOT NULL
    GROUP BY STATUS_ID, bucket_id
)
GROUP BY bucket_id
ORDER BY bucket_id
;

DROP TABLE IF EXISTS Degree_COMPLETE_CAST_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_STATUS_ID;

-- Create aggregator table Degree_COMPLETE_CAST_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_STATUS_ID for Histogram COMPLETE_CAST_MOVIE_ID_ID_TITLE.TITLE_PRODUCTION_YEAR -- FKPK_RANGE
CREATE TEMP TABLE Degree_COMPLETE_CAST_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_STATUS_ID AS
SELECT
    COMPLETE_CAST_MOVIE_ID_ID_TITLE.TITLE_PRODUCTION_YEAR AS PRODUCTION_YEAR,
    COMPLETE_CAST_MOVIE_ID_ID_TITLE.STATUS_ID AS STATUS_ID,
    COUNT(*) AS deg
FROM COMPLETE_CAST_MOVIE_ID_ID_TITLE

WHERE COMPLETE_CAST_MOVIE_ID_ID_TITLE.STATUS_ID IS NOT NULL
GROUP BY
    COMPLETE_CAST_MOVIE_ID_ID_TITLE.TITLE_PRODUCTION_YEAR, COMPLETE_CAST_MOVIE_ID_ID_TITLE.STATUS_ID
;

INSERT INTO norms(

    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
pred_value_id,
l0, l1, l2, l3, l_inf
)
SELECT
    
    'COMPLETE_CAST' AS relation_name,
    'STATUS_ID' AS join_var_name,
    'RANGE' AS aggregator_name,
    'PRODUCTION_YEAR' AS pred_col_name,
    'MOVIE_ID' AS fk_join_var_name,
    'TITLE' AS pk_relation_name,
    'ID' AS pk_join_var_name,
    
    bucket_id     AS pred_value,
    COUNT(*) AS l0,
    SUM(POWER(deg, 1)) AS l1,
    SUM(POWER(deg, 2)) AS l2,
    SUM(POWER(deg, 3)) AS l3,
    MAX(deg) AS l_inf
FROM 
(
  SELECT
        STATUS_ID, bucket_id, SUM(deg) as deg
        FROM Degree_COMPLETE_CAST_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_STATUS_ID d
        JOIN TITLE_PRODUCTION_YEAR_histogram h
        ON (h.lower_bound IS NULL OR d.PRODUCTION_YEAR >= h.lower_bound)
        AND (h.upper_bound IS NULL OR d.PRODUCTION_YEAR <= h.upper_bound)
    WHERE STATUS_ID IS NOT NULL AND bucket_id IS NOT NULL
    GROUP BY STATUS_ID, bucket_id
)
GROUP BY bucket_id
ORDER BY bucket_id
;

