DROP TABLE IF EXISTS Degree_INFO_TYPE_INFO_ID;

-- Create aggregator table Degree_INFO_TYPE_INFO_ID for MCV INFO_TYPE.INFO -- MCV
CREATE TEMP TABLE Degree_INFO_TYPE_INFO_ID AS
SELECT
    mcvt.mcv_id AS mcv_id,
    INFO_TYPE.ID AS ID,
    COUNT(*) AS deg
FROM INFO_TYPE
JOIN INFO_TYPE_INFO_mcv mcvt ON INFO_TYPE.INFO = mcvt.INFO
WHERE INFO_TYPE.ID IS NOT NULL
GROUP BY
    mcvt.mcv_id, INFO_TYPE.ID
;

INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'INFO_TYPE' AS relation_name,
    'ID' AS join_var_name,
    'MCV' AS aggregator_name,
    'INFO' AS pred_col_name,
    NULL AS fk_join_var_name,
    NULL AS pk_relation_name,
    NULL AS pk_join_var_name,
    
    mcv_id AS pred_value,
    COUNT(*) AS l0,
    SUM(POWER(deg, 1)) AS l1,
    SUM(POWER(deg, 2)) AS l2,
    SUM(POWER(deg, 3)) AS l3,
    MAX(deg) AS l_inf
FROM Degree_INFO_TYPE_INFO_ID
GROUP BY mcv_id
;

DROP TABLE IF EXISTS Degree_INFO_TYPE_INFO_ID;

-- Create aggregator table Degree_INFO_TYPE_INFO_ID for NONMCV INFO_TYPE.INFO -- MCV
CREATE TEMP TABLE Degree_INFO_TYPE_INFO_ID AS
SELECT
    INFO_TYPE.INFO AS INFO,
    INFO_TYPE.ID AS ID,
    COUNT(*) AS deg
FROM INFO_TYPE
LEFT JOIN INFO_TYPE_INFO_mcv mcvt ON INFO_TYPE.INFO = mcvt.INFO
WHERE INFO_TYPE.ID IS NOT NULL AND mcvt.mcv_id IS NULL 
GROUP BY
    INFO_TYPE.INFO, INFO_TYPE.ID
;

-- Insert into norms for Non-MCV INFO_TYPE INFO ID NONMCV
-- Among all non-MCV values in Degree_INFO_TYPE_INFO_ID, find max of each Lp
WITH perValue AS (
  SELECT
    INFO,
    COUNT(*) AS l0, SUM(POWER(deg, 1)) AS l1, SUM(POWER(deg, 2)) AS l2, SUM(POWER(deg, 3)) AS l3, MAX(deg) AS l_inf
  FROM Degree_INFO_TYPE_INFO_ID
  GROUP BY INFO
  HAVING INFO IS NOT NULL
)
INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'INFO_TYPE' AS relation_name,
    'ID' AS join_var_name,
    'NONMCV' AS aggregator_name,
    'INFO' AS pred_col_name,
    NULL AS fk_join_var_name,
    NULL AS pk_relation_name,
    NULL AS pk_join_var_name,
    
  NULL              AS pred_value_id,
  MAX(l0) AS l0, MAX(l1) AS l1, MAX(l2) AS l2, MAX(l3) AS l3, MAX(l_inf) AS l_inf
FROM perValue
HAVING COUNT(*) > 0  -- If you need to ensure some rows are returned
;

