    COMPANY_NAME.NAME AS COMPANY_NAME_NAME, COMPANY_NAME.COUNTRY_CODE AS COMPANY_NAME_COUNTRY_CODE
FROM MOVIE_COMPANIES
JOIN COMPANY_NAME
  ON MOVIE_COMPANIES.COMPANY_ID = COMPANY_NAME.ID
;

