DROP TABLE IF EXISTS Degree_MOVIE_COMPANIES_NOTE_COMPANY_ID;

-- Create aggregator table Degree_MOVIE_COMPANIES_NOTE_COMPANY_ID for MCV MOVIE_COMPANIES.NOTE -- MCV
CREATE TEMP TABLE Degree_MOVIE_COMPANIES_NOTE_COMPANY_ID AS
SELECT
    mcvt.mcv_id AS mcv_id,
    MOVIE_COMPANIES.COMPANY_ID AS COMPANY_ID,
    COUNT(*) AS deg
FROM MOVIE_COMPANIES
JOIN MOVIE_COMPANIES_NOTE_mcv mcvt ON MOVIE_COMPANIES.NOTE = mcvt.NOTE
WHERE MOVIE_COMPANIES.COMPANY_ID IS NOT NULL
GROUP BY
    mcvt.mcv_id, MOVIE_COMPANIES.COMPANY_ID
;

INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'MOVIE_COMPANIES' AS relation_name,
    'COMPANY_ID' AS join_var_name,
    'MCV' AS aggregator_name,
    'NOTE' AS pred_col_name,
    NULL AS fk_join_var_name,
    NULL AS pk_relation_name,
    NULL AS pk_join_var_name,
    
    mcv_id AS pred_value,
    COUNT(*) AS l0,
    SUM(POWER(deg, 1)) AS l1,
    SUM(POWER(deg, 2)) AS l2,
    SUM(POWER(deg, 3)) AS l3,
    MAX(deg) AS l_inf
FROM Degree_MOVIE_COMPANIES_NOTE_COMPANY_ID
GROUP BY mcv_id
;

DROP TABLE IF EXISTS Degree_MOVIE_COMPANIES_NOTE_COMPANY_ID;

-- Create aggregator table Degree_MOVIE_COMPANIES_NOTE_COMPANY_ID for NONMCV MOVIE_COMPANIES.NOTE -- MCV
CREATE TEMP TABLE Degree_MOVIE_COMPANIES_NOTE_COMPANY_ID AS
SELECT
    MOVIE_COMPANIES.NOTE AS NOTE,
    MOVIE_COMPANIES.COMPANY_ID AS COMPANY_ID,
    COUNT(*) AS deg
FROM MOVIE_COMPANIES
LEFT JOIN MOVIE_COMPANIES_NOTE_mcv mcvt ON MOVIE_COMPANIES.NOTE = mcvt.NOTE
WHERE MOVIE_COMPANIES.COMPANY_ID IS NOT NULL AND mcvt.mcv_id IS NULL 
GROUP BY
    MOVIE_COMPANIES.NOTE, MOVIE_COMPANIES.COMPANY_ID
;

-- Insert into norms for Non-MCV MOVIE_COMPANIES NOTE COMPANY_ID NONMCV
-- Among all non-MCV values in Degree_MOVIE_COMPANIES_NOTE_COMPANY_ID, find max of each Lp
WITH perValue AS (
  SELECT
    NOTE,
    COUNT(*) AS l0, SUM(POWER(deg, 1)) AS l1, SUM(POWER(deg, 2)) AS l2, SUM(POWER(deg, 3)) AS l3, MAX(deg) AS l_inf
  FROM Degree_MOVIE_COMPANIES_NOTE_COMPANY_ID
  GROUP BY NOTE
  HAVING NOTE IS NOT NULL
)
INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'MOVIE_COMPANIES' AS relation_name,
    'COMPANY_ID' AS join_var_name,
    'NONMCV' AS aggregator_name,
    'NOTE' AS pred_col_name,
    NULL AS fk_join_var_name,
    NULL AS pk_relation_name,
    NULL AS pk_join_var_name,
    
  NULL              AS pred_value_id,
  MAX(l0) AS l0, MAX(l1) AS l1, MAX(l2) AS l2, MAX(l3) AS l3, MAX(l_inf) AS l_inf
FROM perValue
HAVING COUNT(*) > 0  -- If you need to ensure some rows are returned
;

DROP TABLE IF EXISTS Degree_MOVIE_COMPANIES_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_COMPANY_ID;

-- Create aggregator table Degree_MOVIE_COMPANIES_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_COMPANY_ID for MCV MOVIE_COMPANIES_MOVIE_ID_ID_TITLE.TITLE_PRODUCTION_YEAR -- FKPK_MCV
CREATE TEMP TABLE Degree_MOVIE_COMPANIES_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_COMPANY_ID AS
SELECT
    mcvt.mcv_id AS mcv_id,
    MOVIE_COMPANIES_MOVIE_ID_ID_TITLE.COMPANY_ID AS COMPANY_ID,
    COUNT(*) AS deg
FROM MOVIE_COMPANIES_MOVIE_ID_ID_TITLE
JOIN TITLE_PRODUCTION_YEAR_mcv mcvt ON MOVIE_COMPANIES_MOVIE_ID_ID_TITLE.TITLE_PRODUCTION_YEAR = mcvt.PRODUCTION_YEAR
WHERE MOVIE_COMPANIES_MOVIE_ID_ID_TITLE.COMPANY_ID IS NOT NULL
GROUP BY
    mcvt.mcv_id, MOVIE_COMPANIES_MOVIE_ID_ID_TITLE.COMPANY_ID
;

