DROP TABLE IF EXISTS MOVIE_INFO_MOVIE_ID_ID_TITLE;

-- Create temp table MOVIE_INFO_MOVIE_ID_ID_TITLE (FK->PK join)
CREATE TEMP TABLE MOVIE_INFO_MOVIE_ID_ID_TITLE AS
SELECT
    MOVIE_INFO.ID AS ID, MOVIE_INFO.MOVIE_ID AS MOVIE_ID, MOVIE_INFO.INFO_TYPE_ID AS INFO_TYPE_ID,
    TITLE.TITLE AS TITLE_TITLE, TITLE.PRODUCTION_YEAR AS TITLE_PRODUCTION_YEAR, TITLE.EPISODE_NR AS TITLE_EPISODE_NR
FROM MOVIE_INFO
JOIN TITLE
  ON MOVIE_INFO.MOVIE_ID = TITLE.ID
;

DROP TABLE IF EXISTS MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE;

-- Create temp table MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE (FK->PK join)
CREATE TEMP TABLE MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE AS
SELECT
    MOVIE_INFO.ID AS ID, MOVIE_INFO.MOVIE_ID AS MOVIE_ID, MOVIE_INFO.INFO_TYPE_ID AS INFO_TYPE_ID,
    INFO_TYPE.INFO AS INFO_TYPE_INFO
FROM MOVIE_INFO
JOIN INFO_TYPE
  ON MOVIE_INFO.INFO_TYPE_ID = INFO_TYPE.ID
;

DROP TABLE IF EXISTS Degree_MOVIE_INFO_ID;

-- Create aggregator table Degree_MOVIE_INFO_ID
CREATE TEMP TABLE Degree_MOVIE_INFO_ID AS
SELECT
    MOVIE_INFO.ID AS ID,
    COUNT(*) AS deg
FROM MOVIE_INFO

WHERE MOVIE_INFO.ID IS NOT NULL
GROUP BY
    MOVIE_INFO.ID
HAVING COUNT(*) > 0
ORDER BY deg DESC
;

