)
SELECT
    
    'MOVIE_INFO' AS relation_name,
    'INFO_TYPE_ID' AS join_var_name,
    'RANGE' AS aggregator_name,
    'EPISODE_NR' AS pred_col_name,
    'MOVIE_ID' AS fk_join_var_name,
    'TITLE' AS pk_relation_name,
    'ID' AS pk_join_var_name,
    
    bucket_id     AS pred_value,
    COUNT(*) AS l0,
    SUM(POWER(deg, 1)) AS l1,
    SUM(POWER(deg, 2)) AS l2,
    SUM(POWER(deg, 3)) AS l3,
    MAX(deg) AS l_inf
FROM 
(
  SELECT
        INFO_TYPE_ID, bucket_id, SUM(deg) as deg
        FROM Degree_MOVIE_INFO_MOVIE_ID_ID_TITLE_EPISODE_NR_INFO_TYPE_ID d
        JOIN TITLE_EPISODE_NR_histogram h
        ON (h.lower_bound IS NULL OR d.EPISODE_NR >= h.lower_bound)
        AND (h.upper_bound IS NULL OR d.EPISODE_NR <= h.upper_bound)
    WHERE INFO_TYPE_ID IS NOT NULL AND bucket_id IS NOT NULL
    GROUP BY INFO_TYPE_ID, bucket_id
)
GROUP BY bucket_id
ORDER BY bucket_id
;

DROP TABLE IF EXISTS Degree_MOVIE_INFO_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_INFO_TYPE_ID;

-- Create aggregator table Degree_MOVIE_INFO_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_INFO_TYPE_ID for Histogram MOVIE_INFO_MOVIE_ID_ID_TITLE.TITLE_PRODUCTION_YEAR -- FKPK_RANGE
CREATE TEMP TABLE Degree_MOVIE_INFO_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_INFO_TYPE_ID AS
SELECT
