DROP TABLE IF EXISTS Degree_MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE_INFO_INFO_TYPE_ID;

-- Create aggregator table Degree_MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE_INFO_INFO_TYPE_ID for MCV MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE.INFO_TYPE_INFO -- FKPK_MCV
CREATE TEMP TABLE Degree_MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE_INFO_INFO_TYPE_ID AS
SELECT
    mcvt.mcv_id AS mcv_id,
    MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE.INFO_TYPE_ID AS INFO_TYPE_ID,
    COUNT(*) AS deg
FROM MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE
JOIN INFO_TYPE_INFO_mcv mcvt ON MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE.INFO_TYPE_INFO = mcvt.INFO
WHERE MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE.INFO_TYPE_ID IS NOT NULL
GROUP BY
    mcvt.mcv_id, MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE.INFO_TYPE_ID
;

