DROP TABLE IF EXISTS Degree_MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE_INFO_INFO_TYPE_ID;

-- Create aggregator table Degree_MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE_INFO_INFO_TYPE_ID for NONMCV MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE.INFO_TYPE_INFO -- FKPK_MCV
CREATE TEMP TABLE Degree_MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE_INFO_INFO_TYPE_ID AS
SELECT
    MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE.INFO_TYPE_INFO AS INFO,
    MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE.INFO_TYPE_ID AS INFO_TYPE_ID,
    COUNT(*) AS deg
FROM MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE
LEFT JOIN INFO_TYPE_INFO_mcv mcvt ON MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE.INFO_TYPE_INFO = mcvt.INFO
WHERE MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE.INFO_TYPE_ID IS NOT NULL AND mcvt.mcv_id IS NULL 
GROUP BY
    MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE.INFO_TYPE_INFO, MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE.INFO_TYPE_ID
;

-- Insert into norms for Non-MCV MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE INFO INFO_TYPE_ID NONMCV
-- Among all non-MCV values in Degree_MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE_INFO_INFO_TYPE_ID, find max of each Lp
WITH perValue AS (
  SELECT
    INFO,
    COUNT(*) AS l0, SUM(POWER(deg, 1)) AS l1, SUM(POWER(deg, 2)) AS l2, SUM(POWER(deg, 3)) AS l3, MAX(deg) AS l_inf
  FROM Degree_MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE_INFO_INFO_TYPE_ID
  GROUP BY INFO
  HAVING INFO IS NOT NULL
)
