DROP TABLE IF EXISTS MOVIE_KEYWORD_MOVIE_ID_ID_TITLE;

-- Create temp table MOVIE_KEYWORD_MOVIE_ID_ID_TITLE (FK->PK join)
CREATE TEMP TABLE MOVIE_KEYWORD_MOVIE_ID_ID_TITLE AS
SELECT
    MOVIE_KEYWORD.ID AS ID, MOVIE_KEYWORD.MOVIE_ID AS MOVIE_ID, MOVIE_KEYWORD.KEYWORD_ID AS KEYWORD_ID,
    TITLE.TITLE AS TITLE_TITLE, TITLE.PRODUCTION_YEAR AS TITLE_PRODUCTION_YEAR, TITLE.EPISODE_NR AS TITLE_EPISODE_NR
FROM MOVIE_KEYWORD
JOIN TITLE
  ON MOVIE_KEYWORD.MOVIE_ID = TITLE.ID
;

DROP TABLE IF EXISTS MOVIE_KEYWORD_KEYWORD_ID_ID_KEYWORD;

-- Create temp table MOVIE_KEYWORD_KEYWORD_ID_ID_KEYWORD (FK->PK join)
CREATE TEMP TABLE MOVIE_KEYWORD_KEYWORD_ID_ID_KEYWORD AS
SELECT
    MOVIE_KEYWORD.ID AS ID, MOVIE_KEYWORD.MOVIE_ID AS MOVIE_ID, MOVIE_KEYWORD.KEYWORD_ID AS KEYWORD_ID,
    KEYWORD.KEYWORD AS KEYWORD_KEYWORD
FROM MOVIE_KEYWORD
JOIN KEYWORD
  ON MOVIE_KEYWORD.KEYWORD_ID = KEYWORD.ID
;

DROP TABLE IF EXISTS Degree_MOVIE_KEYWORD_ID;

-- Create aggregator table Degree_MOVIE_KEYWORD_ID
CREATE TEMP TABLE Degree_MOVIE_KEYWORD_ID AS
SELECT
    MOVIE_KEYWORD.ID AS ID,
    COUNT(*) AS deg
FROM MOVIE_KEYWORD

WHERE MOVIE_KEYWORD.ID IS NOT NULL
GROUP BY
    MOVIE_KEYWORD.ID
HAVING COUNT(*) > 0
ORDER BY deg DESC
;

