DROP TABLE IF EXISTS Degree_MOVIE_KEYWORD_KEYWORD_ID_ID_KEYWORD_KEYWORD_MOVIE_ID;

-- Create aggregator table Degree_MOVIE_KEYWORD_KEYWORD_ID_ID_KEYWORD_KEYWORD_MOVIE_ID for NONMCV MOVIE_KEYWORD_KEYWORD_ID_ID_KEYWORD.KEYWORD_KEYWORD -- FKPK_MCV
CREATE TEMP TABLE Degree_MOVIE_KEYWORD_KEYWORD_ID_ID_KEYWORD_KEYWORD_MOVIE_ID AS
SELECT
    MOVIE_KEYWORD_KEYWORD_ID_ID_KEYWORD.KEYWORD_KEYWORD AS KEYWORD,
    MOVIE_KEYWORD_KEYWORD_ID_ID_KEYWORD.MOVIE_ID AS MOVIE_ID,
    COUNT(*) AS deg
FROM MOVIE_KEYWORD_KEYWORD_ID_ID_KEYWORD
LEFT JOIN KEYWORD_KEYWORD_mcv mcvt ON MOVIE_KEYWORD_KEYWORD_ID_ID_KEYWORD.KEYWORD_KEYWORD = mcvt.KEYWORD
WHERE MOVIE_KEYWORD_KEYWORD_ID_ID_KEYWORD.MOVIE_ID IS NOT NULL AND mcvt.mcv_id IS NULL 
GROUP BY
    MOVIE_KEYWORD_KEYWORD_ID_ID_KEYWORD.KEYWORD_KEYWORD, MOVIE_KEYWORD_KEYWORD_ID_ID_KEYWORD.MOVIE_ID
;

-- Insert into norms for Non-MCV MOVIE_KEYWORD_KEYWORD_ID_ID_KEYWORD KEYWORD MOVIE_ID NONMCV
-- Among all non-MCV values in Degree_MOVIE_KEYWORD_KEYWORD_ID_ID_KEYWORD_KEYWORD_MOVIE_ID, find max of each Lp
WITH perValue AS (
  SELECT
    KEYWORD,
    COUNT(*) AS l0, SUM(POWER(deg, 1)) AS l1, SUM(POWER(deg, 2)) AS l2, SUM(POWER(deg, 3)) AS l3, MAX(deg) AS l_inf
  FROM Degree_MOVIE_KEYWORD_KEYWORD_ID_ID_KEYWORD_KEYWORD_MOVIE_ID
  GROUP BY KEYWORD
  HAVING KEYWORD IS NOT NULL
)
INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'MOVIE_KEYWORD' AS relation_name,
    'MOVIE_ID' AS join_var_name,
    'NONMCV' AS aggregator_name,
    'KEYWORD' AS pred_col_name,
    'KEYWORD_ID' AS fk_join_var_name,
    'KEYWORD' AS pk_relation_name,
    'ID' AS pk_join_var_name,
    
  NULL              AS pred_value_id,
  MAX(l0) AS l0, MAX(l1) AS l1, MAX(l2) AS l2, MAX(l3) AS l3, MAX(l_inf) AS l_inf
FROM perValue
HAVING COUNT(*) > 0  -- If you need to ensure some rows are returned
;

DROP TABLE IF EXISTS Degree_MOVIE_KEYWORD_KEYWORD_ID;

-- Create aggregator table Degree_MOVIE_KEYWORD_KEYWORD_ID
CREATE TEMP TABLE Degree_MOVIE_KEYWORD_KEYWORD_ID AS
SELECT
    MOVIE_KEYWORD.KEYWORD_ID AS KEYWORD_ID,
    COUNT(*) AS deg
FROM MOVIE_KEYWORD

WHERE MOVIE_KEYWORD.KEYWORD_ID IS NOT NULL
GROUP BY
    MOVIE_KEYWORD.KEYWORD_ID
HAVING COUNT(*) > 0
ORDER BY deg DESC
;

