DROP TABLE IF EXISTS MOVIE_LINK_MOVIE_ID_ID_TITLE;

-- Create temp table MOVIE_LINK_MOVIE_ID_ID_TITLE (FK->PK join)
CREATE TEMP TABLE MOVIE_LINK_MOVIE_ID_ID_TITLE AS
SELECT
    MOVIE_LINK.ID AS ID, MOVIE_LINK.MOVIE_ID AS MOVIE_ID, MOVIE_LINK.LINKED_MOVIE_ID AS LINKED_MOVIE_ID, MOVIE_LINK.LINK_TYPE_ID AS LINK_TYPE_ID,
    TITLE.TITLE AS TITLE_TITLE, TITLE.PRODUCTION_YEAR AS TITLE_PRODUCTION_YEAR, TITLE.EPISODE_NR AS TITLE_EPISODE_NR
FROM MOVIE_LINK
JOIN TITLE
  ON MOVIE_LINK.MOVIE_ID = TITLE.ID
;

DROP TABLE IF EXISTS MOVIE_LINK_LINKED_MOVIE_ID_ID_TITLE;

-- Create temp table MOVIE_LINK_LINKED_MOVIE_ID_ID_TITLE (FK->PK join)
CREATE TEMP TABLE MOVIE_LINK_LINKED_MOVIE_ID_ID_TITLE AS
SELECT
    MOVIE_LINK.ID AS ID, MOVIE_LINK.MOVIE_ID AS MOVIE_ID, MOVIE_LINK.LINKED_MOVIE_ID AS LINKED_MOVIE_ID, MOVIE_LINK.LINK_TYPE_ID AS LINK_TYPE_ID,
    TITLE.TITLE AS TITLE_TITLE, TITLE.PRODUCTION_YEAR AS TITLE_PRODUCTION_YEAR, TITLE.EPISODE_NR AS TITLE_EPISODE_NR
FROM MOVIE_LINK
JOIN TITLE
  ON MOVIE_LINK.LINKED_MOVIE_ID = TITLE.ID
;

DROP TABLE IF EXISTS MOVIE_LINK_LINK_TYPE_ID_ID_LINK_TYPE;

-- Create temp table MOVIE_LINK_LINK_TYPE_ID_ID_LINK_TYPE (FK->PK join)
CREATE TEMP TABLE MOVIE_LINK_LINK_TYPE_ID_ID_LINK_TYPE AS
SELECT
    MOVIE_LINK.ID AS ID, MOVIE_LINK.MOVIE_ID AS MOVIE_ID, MOVIE_LINK.LINKED_MOVIE_ID AS LINKED_MOVIE_ID, MOVIE_LINK.LINK_TYPE_ID AS LINK_TYPE_ID,
    LINK_TYPE.LINK AS LINK_TYPE_LINK
FROM MOVIE_LINK
JOIN LINK_TYPE
  ON MOVIE_LINK.LINK_TYPE_ID = LINK_TYPE.ID
;

