-- Create aggregator table Degree_MOVIE_LINK_LINK_TYPE_ID_ID_LINK_TYPE_LINK_MOVIE_ID for NONMCV MOVIE_LINK_LINK_TYPE_ID_ID_LINK_TYPE.LINK_TYPE_LINK -- FKPK_MCV
CREATE TEMP TABLE Degree_MOVIE_LINK_LINK_TYPE_ID_ID_LINK_TYPE_LINK_MOVIE_ID AS
SELECT
    MOVIE_LINK_LINK_TYPE_ID_ID_LINK_TYPE.LINK_TYPE_LINK AS LINK,
    MOVIE_LINK_LINK_TYPE_ID_ID_LINK_TYPE.MOVIE_ID AS MOVIE_ID,
    COUNT(*) AS deg
FROM MOVIE_LINK_LINK_TYPE_ID_ID_LINK_TYPE
LEFT JOIN LINK_TYPE_LINK_mcv mcvt ON MOVIE_LINK_LINK_TYPE_ID_ID_LINK_TYPE.LINK_TYPE_LINK = mcvt.LINK
WHERE MOVIE_LINK_LINK_TYPE_ID_ID_LINK_TYPE.MOVIE_ID IS NOT NULL AND mcvt.mcv_id IS NULL 
