-- Among all non-MCV values in Degree_MOVIE_LINK_LINK_TYPE_ID_ID_LINK_TYPE_LINK_MOVIE_ID, find max of each Lp
WITH perValue AS (
  SELECT
    LINK,
    COUNT(*) AS l0, SUM(POWER(deg, 1)) AS l1, SUM(POWER(deg, 2)) AS l2, SUM(POWER(deg, 3)) AS l3, MAX(deg) AS l_inf
  FROM Degree_MOVIE_LINK_LINK_TYPE_ID_ID_LINK_TYPE_LINK_MOVIE_ID
  GROUP BY LINK
  HAVING LINK IS NOT NULL
)
