        LINKED_MOVIE_ID, bucket_id, SUM(deg) as deg
        FROM Degree_MOVIE_LINK_LINKED_MOVIE_ID_ID_TITLE_EPISODE_NR_LINKED_MOVIE_ID d
        JOIN TITLE_EPISODE_NR_histogram h
        ON (h.lower_bound IS NULL OR d.EPISODE_NR >= h.lower_bound)
        AND (h.upper_bound IS NULL OR d.EPISODE_NR <= h.upper_bound)
    WHERE LINKED_MOVIE_ID IS NOT NULL AND bucket_id IS NOT NULL
    GROUP BY LINKED_MOVIE_ID, bucket_id
)
GROUP BY bucket_id
ORDER BY bucket_id
;

