DROP TABLE IF EXISTS Degree_NAME_GENDER_ID;

-- Create aggregator table Degree_NAME_GENDER_ID for MCV NAME.GENDER -- MCV
CREATE TEMP TABLE Degree_NAME_GENDER_ID AS
SELECT
    mcvt.mcv_id AS mcv_id,
    NAME.ID AS ID,
    COUNT(*) AS deg
FROM NAME
JOIN NAME_GENDER_mcv mcvt ON NAME.GENDER = mcvt.GENDER
WHERE NAME.ID IS NOT NULL
GROUP BY
    mcvt.mcv_id, NAME.ID
;

INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'NAME' AS relation_name,
    'ID' AS join_var_name,
    'MCV' AS aggregator_name,
    'GENDER' AS pred_col_name,
    NULL AS fk_join_var_name,
    NULL AS pk_relation_name,
    NULL AS pk_join_var_name,
    
    mcv_id AS pred_value,
    COUNT(*) AS l0,
    SUM(POWER(deg, 1)) AS l1,
    SUM(POWER(deg, 2)) AS l2,
    SUM(POWER(deg, 3)) AS l3,
    MAX(deg) AS l_inf
FROM Degree_NAME_GENDER_ID
GROUP BY mcv_id
;

DROP TABLE IF EXISTS Degree_NAME_GENDER_ID;

-- Create aggregator table Degree_NAME_GENDER_ID for NONMCV NAME.GENDER -- MCV
CREATE TEMP TABLE Degree_NAME_GENDER_ID AS
SELECT
    NAME.GENDER AS GENDER,
    NAME.ID AS ID,
    COUNT(*) AS deg
FROM NAME
LEFT JOIN NAME_GENDER_mcv mcvt ON NAME.GENDER = mcvt.GENDER
WHERE NAME.ID IS NOT NULL AND mcvt.mcv_id IS NULL 
GROUP BY
    NAME.GENDER, NAME.ID
;

-- Insert into norms for Non-MCV NAME GENDER ID NONMCV
-- Among all non-MCV values in Degree_NAME_GENDER_ID, find max of each Lp
WITH perValue AS (
  SELECT
    GENDER,
    COUNT(*) AS l0, SUM(POWER(deg, 1)) AS l1, SUM(POWER(deg, 2)) AS l2, SUM(POWER(deg, 3)) AS l3, MAX(deg) AS l_inf
  FROM Degree_NAME_GENDER_ID
  GROUP BY GENDER
  HAVING GENDER IS NOT NULL
)
INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'NAME' AS relation_name,
    'ID' AS join_var_name,
    'NONMCV' AS aggregator_name,
    'GENDER' AS pred_col_name,
    NULL AS fk_join_var_name,
    NULL AS pk_relation_name,
    NULL AS pk_join_var_name,
    
  NULL              AS pred_value_id,
  MAX(l0) AS l0, MAX(l1) AS l1, MAX(l2) AS l2, MAX(l3) AS l3, MAX(l_inf) AS l_inf
FROM perValue
HAVING COUNT(*) > 0  -- If you need to ensure some rows are returned
;

