DROP TABLE IF EXISTS Degree_PERSON_INFO_NOTE_ID;

-- Create aggregator table Degree_PERSON_INFO_NOTE_ID for MCV PERSON_INFO.NOTE -- MCV
CREATE TEMP TABLE Degree_PERSON_INFO_NOTE_ID AS
SELECT
    mcvt.mcv_id AS mcv_id,
    PERSON_INFO.ID AS ID,
    COUNT(*) AS deg
FROM PERSON_INFO
JOIN PERSON_INFO_NOTE_mcv mcvt ON PERSON_INFO.NOTE = mcvt.NOTE
WHERE PERSON_INFO.ID IS NOT NULL
GROUP BY
    mcvt.mcv_id, PERSON_INFO.ID
;

INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'PERSON_INFO' AS relation_name,
    'ID' AS join_var_name,
    'MCV' AS aggregator_name,
    'NOTE' AS pred_col_name,
    NULL AS fk_join_var_name,
    NULL AS pk_relation_name,
    NULL AS pk_join_var_name,
    
    mcv_id AS pred_value,
    COUNT(*) AS l0,
    SUM(POWER(deg, 1)) AS l1,
    SUM(POWER(deg, 2)) AS l2,
    SUM(POWER(deg, 3)) AS l3,
    MAX(deg) AS l_inf
FROM Degree_PERSON_INFO_NOTE_ID
GROUP BY mcv_id
;

DROP TABLE IF EXISTS Degree_PERSON_INFO_NOTE_ID;

-- Create aggregator table Degree_PERSON_INFO_NOTE_ID for NONMCV PERSON_INFO.NOTE -- MCV
CREATE TEMP TABLE Degree_PERSON_INFO_NOTE_ID AS
SELECT
    PERSON_INFO.NOTE AS NOTE,
    PERSON_INFO.ID AS ID,
    COUNT(*) AS deg
FROM PERSON_INFO
LEFT JOIN PERSON_INFO_NOTE_mcv mcvt ON PERSON_INFO.NOTE = mcvt.NOTE
WHERE PERSON_INFO.ID IS NOT NULL AND mcvt.mcv_id IS NULL 
GROUP BY
    PERSON_INFO.NOTE, PERSON_INFO.ID
;

-- Insert into norms for Non-MCV PERSON_INFO NOTE ID NONMCV
-- Among all non-MCV values in Degree_PERSON_INFO_NOTE_ID, find max of each Lp
WITH perValue AS (
  SELECT
    NOTE,
    COUNT(*) AS l0, SUM(POWER(deg, 1)) AS l1, SUM(POWER(deg, 2)) AS l2, SUM(POWER(deg, 3)) AS l3, MAX(deg) AS l_inf
  FROM Degree_PERSON_INFO_NOTE_ID
  GROUP BY NOTE
  HAVING NOTE IS NOT NULL
)
INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'PERSON_INFO' AS relation_name,
    'ID' AS join_var_name,
    'NONMCV' AS aggregator_name,
    'NOTE' AS pred_col_name,
    NULL AS fk_join_var_name,
    NULL AS pk_relation_name,
    NULL AS pk_join_var_name,
    
  NULL              AS pred_value_id,
  MAX(l0) AS l0, MAX(l1) AS l1, MAX(l2) AS l2, MAX(l3) AS l3, MAX(l_inf) AS l_inf
FROM perValue
HAVING COUNT(*) > 0  -- If you need to ensure some rows are returned
;

DROP TABLE IF EXISTS Degree_PERSON_INFO_PERSON_ID_ID_NAME_GENDER_ID;

-- Create aggregator table Degree_PERSON_INFO_PERSON_ID_ID_NAME_GENDER_ID for MCV PERSON_INFO_PERSON_ID_ID_NAME.NAME_GENDER -- FKPK_MCV
CREATE TEMP TABLE Degree_PERSON_INFO_PERSON_ID_ID_NAME_GENDER_ID AS
SELECT
    mcvt.mcv_id AS mcv_id,
    PERSON_INFO_PERSON_ID_ID_NAME.ID AS ID,
    COUNT(*) AS deg
FROM PERSON_INFO_PERSON_ID_ID_NAME
JOIN NAME_GENDER_mcv mcvt ON PERSON_INFO_PERSON_ID_ID_NAME.NAME_GENDER = mcvt.GENDER
WHERE PERSON_INFO_PERSON_ID_ID_NAME.ID IS NOT NULL
GROUP BY
    mcvt.mcv_id, PERSON_INFO_PERSON_ID_ID_NAME.ID
;

INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'PERSON_INFO' AS relation_name,
    'ID' AS join_var_name,
    'MCV' AS aggregator_name,
    'GENDER' AS pred_col_name,
    'PERSON_ID' AS fk_join_var_name,
    'NAME' AS pk_relation_name,
