DROP TABLE IF EXISTS Degree_PERSON_INFO_NOTE_PERSON_ID;

-- Create aggregator table Degree_PERSON_INFO_NOTE_PERSON_ID for MCV PERSON_INFO.NOTE -- MCV
CREATE TEMP TABLE Degree_PERSON_INFO_NOTE_PERSON_ID AS
SELECT
    mcvt.mcv_id AS mcv_id,
    PERSON_INFO.PERSON_ID AS PERSON_ID,
    COUNT(*) AS deg
FROM PERSON_INFO
JOIN PERSON_INFO_NOTE_mcv mcvt ON PERSON_INFO.NOTE = mcvt.NOTE
WHERE PERSON_INFO.PERSON_ID IS NOT NULL
GROUP BY
    mcvt.mcv_id, PERSON_INFO.PERSON_ID
;

