LEFT JOIN NAME_NAME_PCODE_CF_mcv mcvt ON PERSON_INFO_PERSON_ID_ID_NAME.NAME_NAME_PCODE_CF = mcvt.NAME_PCODE_CF
WHERE PERSON_INFO_PERSON_ID_ID_NAME.PERSON_ID IS NOT NULL AND mcvt.mcv_id IS NULL 
GROUP BY
    PERSON_INFO_PERSON_ID_ID_NAME.NAME_NAME_PCODE_CF, PERSON_INFO_PERSON_ID_ID_NAME.PERSON_ID
;

